+        @Test
+        void noCycle_proportional_samplesAndClamps() {
+            var b = new BoundingBox(0, 0, 100, 100);
+            var g = new LinearGradient(
+                0, 0, 1, 0,
+                true, CycleMethod.NO_CYCLE,
+                new Stop(0, Color.RED),
